export const completeEnglishStudySessionBodyCorrectMin = 0;

export const completeEnglishStudySessionBodyWordsMasteredMin = 0;

export const completeEnglishStudySessionBodyDurationSecondsMin = 0;

export const CompleteEnglishStudySessionBody = zod.object({
  attempts: zod.number().min(completeEnglishStudySessionBodyAttemptsMin),
  correct: zod.number().min(completeEnglishStudySessionBodyCorrectMin),
  wordsMastered: zod
    .number()
    .min(completeEnglishStudySessionBodyWordsMasteredMin)
    .optional(),
  durationSeconds: zod
    .number()
    .min(completeEnglishStudySessionBodyDurationSecondsMin)
    .optional(),
});

